# Data Integrity Checker using Hashing
import hashlib
import os
from pathlib import Path

class IntegrityChecker:
    def __init__(self, baseline_file=None):
        self.baseline = {}
        if baseline_file and os.path.exists(baseline_file):
            self.load_baseline(baseline_file)

    def hash_file(self, filepath):
        """Calculate SHA-256 hash of a file."""
        sha256 = hashlib.sha256()
        with open(filepath, 'rb') as f:
            for chunk in iter(lambda: f.read(8192), b''):
                sha256.update(chunk)
        return sha256.hexdigest()

    def create_baseline(self, directory):
        """Create integrity baseline for a directory."""
        baseline = {}
        for filepath in Path(directory).rglob('*'):
            if filepath.is_file():
                baseline[str(filepath)] = self.hash_file(filepath)
        return baseline

    def verify_integrity(self, directory):
        """Verify current files against baseline."""
        modified = []
        added = []
        deleted = []

        current = {}
        for filepath in Path(directory).rglob('*'):
            if filepath.is_file():
                current[str(filepath)] = self.hash_file(filepath)

        for path, hash_val in current.items():
            if path not in self.baseline:
                added.append(path)
            elif self.baseline[path] != hash_val:
                modified.append(path)

        for path in self.baseline:
            if path not in current:
                deleted.append(path)

        return {'modified': modified, 'added': added, 'deleted': deleted}

# Usage
checker = IntegrityChecker()
baseline = checker.create_baseline('/etc')
checker.baseline = baseline
results = checker.verify_integrity('/etc')
print(f"Modified: {len(results['modified'])}, Added: {len(results['added'])}, Deleted: {len(results['deleted'])}")
